import numpy as np

def mcts(n_states: int, n_simulations: int, c: float = 1.414) -> int:
    goal = n_states - 1

    class Node:
        def __init__(self, state, parent=None, action=None):
            self.state = state
            self.parent = parent
            self.action = action
            self.children = []
            self.N = 0
            self.W = 0.0
            self.untried = [0, 1] if state != goal else []

        def ucb(self, c):
            if self.N == 0:
                return float('inf')
            return self.W / self.N + c * np.sqrt(np.log(self.parent.N) / self.N)

        def is_terminal(self):
            return self.state == goal

        def is_fully_expanded(self):
            return len(self.untried) == 0

    def step(state, action):
        return int(np.clip(state + (1 if action == 1 else -1), 0, goal))

    def rollout(state):
        for _ in range(50):
            if state == goal:
                return 1.0
            state = step(state, np.random.randint(2))
        return 0.0

    root = Node(0)

    for _ in range(n_simulations):
        node = root

        while node.is_fully_expanded() and not node.is_terminal():
            node = max(node.children, key=lambda ch: ch.ucb(c))

        if not node.is_terminal() and node.untried:
            action = node.untried.pop()
            s_next = step(node.state, action)
            child = Node(s_next, parent=node, action=action)
            node.children.append(child)
            node = child

        value = rollout(node.state)

        while node is not None:
            node.N += 1
            node.W += value
            node = node.parent

    best = max(root.children, key=lambda ch: ch.N)
    return best.action
